#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_N 300
#define MAX_M 300

int N, K;
int ids[MAX_N][MAX_M];
int id_len[MAX_N];
int visited[MAX_N];

int are_relatives(int i, int j) {
    int common = 0;
    for (int k = 0; k < id_len[i]; k++) {
        for (int l = 0; l < id_len[j]; l++) {
            if (ids[i][k] == ids[j][l]) {
                common++;
            }
        }
    }
    return common >= K;
}

void bfs(int start) {
    int queue[MAX_N];
    int front = 0, rear = 0;
    queue[rear++] = start;
    visited[start] = 1;
    while (front < rear) {
        int u = queue[front++];
        for (int v = 0; v < N; v++) {
            if (!visited[v] && are_relatives(u, v)) {
                queue[rear++] = v;
                visited[v] = 1;
            }
        }
    }
}

int main() {
    scanf("%d %d", &N, &K);
    for (int i = 0; i < N; i++) {
        scanf("%d", &id_len[i]);
        for (int j = 0; j < id_len[i]; j++) {
            scanf("%d", &ids[i][j]);
        }
    }
    bfs(0);
    int count = 0;
    for (int i = 0; i < N; i++) {
        if (visited[i]) {
            count++;
        }
    }
    printf("%d\n", count);
    return 0;
}

