import java.util.Scanner;
import java.util.Queue;
import java.util.LinkedList;
public class Main {
    static int N, K;
    static int[][] ids;
    static int[] id_len;
    static boolean[] visited;

    public static boolean are_relatives(int i, int j) {
        int common = 0;
        for (int k = 0; k < id_len[i]; k++) {
            for (int l = 0; l < id_len[j]; l++) {
                if (ids[i][k] == ids[j][l]) {
                    common++;
                }
            }
        }
        return common >= K;
    }

    public static void bfs(int start) {
        Queue<Integer> q = new LinkedList<>();
        q.add(start);
        visited[start] = true;
        while (!q.isEmpty()) {
            int u = q.poll();
            for (int v = 0; v < N; v++) {
                if (!visited[v] && are_relatives(u, v)) {
                    q.add(v);
                    visited[v] = true;
                }
            }
        }
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        N = sc.nextInt();
        K = sc.nextInt();
        ids = new int[N][];
        id_len = new int[N];
        visited = new boolean[N];
        for (int i = 0; i < N; i++) {
            id_len[i] = sc.nextInt();
            ids[i] = new int[id_len[i]];
            for (int j = 0; j < id_len[i]; j++) {
                ids[i][j] = sc.nextInt();
            }
        }
        bfs(0);
        int count = 0;
        for (int i = 0; i < N; i++) {
            if (visited[i]) {
                count++;
            }
        }
        System.out.println(count);
    }
}

